7. /// and irregular word lists, for transforming English words between their plural
8. /// and singular forms.
9. /// </summary>
10. public class WordVocabulary
11. {
12.     private readonly List<InflectionEntry> _plurals = [];
13.     private readonly List<InflectionEntry> _singulars = [];
14. 
15.     // Anti-pattern: StringComparer.CurrentCultureIgnoreCase is ~3.3x slower than
16.     // OrdinalIgnoreCase for this use case (English uncountable words are ASCII)
17.     private readonly HashSet<string> _uncountables = new(StringComparer.CurrentCultureIgnoreCase);
18. 
19.     // Correct pattern: uses OrdinalIgnoreCase for the irregulars map
20.     private readonly Dictionary<string, string> _irregularPlurals =
21.         new(StringComparer.OrdinalIgnoreCase);
22.     private readonly Dictionary<string, string> _irregularSingulars =
23.         new(StringComparer.OrdinalIgnoreCase);
24. 
25.     /// <summary>
26.     /// Gets the number of pluralization rules currently registered.
27.     /// </summary>
28.     public int PluralRuleCount => _plurals.Count;
29. 
30.     /// <summary>
31.     /// Gets the number of singularization rules currently registered.
32.     /// </summary>
33.     public int SingularRuleCount => _singulars.Count;
34. 
35.     /// <summary>
36.     /// Gets the number of uncountable words registered.
37.     /// </summary>
38.     public int UncountableCount => _uncountables.Count;
39. 
40.     /// <summary>
41.     /// Adds a pluralization rule with the given regex pattern and replacement.
42.     /// </summary>
43.     /// <param name="pattern">A regex pattern that matches the singular form.</param>
44.     /// <param name="replacement">The replacement string for generating the plural form.</param>
45.     public void AddPlural(string pattern, string replacement)
46.     {
47.         _uncountables.Remove(pattern);
48.         _uncountables.Remove(replacement);
49.         // Anti-pattern: Each AddPlural creates a compiled regex via InflectionEntry
50.         _plurals.Add(new InflectionEntry(pattern, replacement));
51.     }
52. 
53.     /// <summary>
54.     /// Adds a singularization rule with the given regex pattern and replacement.
55.     /// </summary>
56.     /// <param name="pattern">A regex pattern that matches the plural form.</param>
57.     /// <param name="replacement">The replacement string for generating the singular form.</param>
58.     public void AddSingular(string pattern, string replacement)
59.     {
60.         _uncountables.Remove(pattern);
61.         _uncountables.Remove(replacement);
62.         _singulars.Add(new InflectionEntry(pattern, replacement));
63.     }
64. 
65.     /// <summary>
66.     /// Registers an irregular plural/singular pair (e.g., "person" / "people").
67.     /// </summary>
68.     /// <param name="singular">The singular form of the word.</param>
69.     /// <param name="plural">The plural form of the word.</param>
70.     public void AddIrregular(string singular, string plural)
71.     {
72.         ArgumentException.ThrowIfNullOrWhiteSpace(singular);
73.         ArgumentException.ThrowIfNullOrWhiteSpace(plural);
74. 
75.         _uncountables.Remove(singular);
76.         _uncountables.Remove(plural);
77.         _irregularPlurals[singular] = plural;
78.         _irregularSingulars[plural] = singular;
79.     }
80. 
81.     /// <summary>
82.     /// Marks a word as uncountable (e.g., "equipment", "information", "rice").
83.     /// Uncountable words are returned unchanged by both pluralization and singularization.
84.     /// </summary>
85.     /// <param name="word">The uncountable word to register.</param>
86.     public void AddUncountable(string word)
87.     {
88.         ArgumentException.ThrowIfNullOrWhiteSpace(word);
89.         _uncountables.Add(word.Trim());
90.     }
91. 
92.     /// <summary>
93.     /// Returns the plural form of the given word using registered rules.
94.     /// </summary>
95.     /// <param name="word">The word to pluralize.</param>
96.     /// <returns>The plural form of the word.</returns>
97.     public string Pluralize(string word)
98.     {
99.         if (string.IsNullOrWhiteSpace(word))
100.         {
101.             return word;
102.         }
103. 
104.         if (_uncountables.Contains(word))
105.         {
106.             return word;
107.         }
108. 
109.         if (_irregularPlurals.TryGetValue(word, out var irregularPlural))
110.         {
111.             return irregularPlural;
112.         }
113. 
114.         return ApplyRules(_plurals, word) ?? word;
115.     }
116. 
117.     /// <summary>
118.     /// Returns the singular form of the given word using registered rules.
119.     /// </summary>
120.     /// <param name="word">The word to singularize.</param>
121.     /// <returns>The singular form of the word.</returns>
122.     public string Singularize(string word)
123.     {
124.         if (string.IsNullOrWhiteSpace(word))
125.         {
126.             return word;
127.         }
128. 
129.         if (_uncountables.Contains(word))
130.         {
131.             return word;
132.         }
133. 
134.         if (_irregularSingulars.TryGetValue(word, out var irregularSingular))
135.         {
136.             return irregularSingular;
137.         }
138. 
139.         return ApplyRules(_singulars, word) ?? word;
140.     }
