/// <summary>
/// Internal rule entry holding a compiled regex and replacement pattern.
/// </summary>
private class InflectionEntry
{
    private readonly Regex _regex;
    private readonly string _replacement;

    public InflectionEntry(string pattern, string replacement)
    {
        _regex = new Regex(pattern, RegexOptions.IgnoreCase | RegexOptions.Compiled);
        _replacement = replacement;
    }

    public string? Apply(string word)
    {
        // Replace returns the original string reference when there is no match,
        // avoiding a redundant IsMatch + Replace double-traversal.
        var result = _regex.Replace(word, _replacement, count: 1);
        return ReferenceEquals(result, word) ? null : result;
    }
}

