17. 
18.     // Caches to avoid repeated regex scans for the same words
19.     private readonly ConcurrentDictionary<string, string> _pluralCache = new(StringComparer.Ordinal);
20.     private readonly ConcurrentDictionary<string, string> _singularCache = new(StringComparer.Ordinal);
21. 
22.     // Uses OrdinalIgnoreCase for the irregulars map
23.     private readonly Dictionary<string, string> _irregularPlurals =
24.         new(StringComparer.OrdinalIgnoreCase);
