37. 
38.     /// <summary>
39.     /// Gets the number of uncountable words registered.
40.     /// </summary>
41.     public int UncountableCount => _uncountables.Count;
42. 
43.     /// <summary>
44.     /// Adds a pluralization rule with the given regex pattern and replacement.
45.     /// </summary>
46.     /// <param name="pattern">A regex pattern that matches the singular form.</param>
47.     /// <param name="replacement">The replacement string for generating the plural form.</param>
48.     public void AddPlural(string pattern, string replacement)
49.     {
50.         _uncountables.Remove(pattern);
