100.     /// <returns>The plural form of the word.</returns>
101.     public string Pluralize(string word)
102.     {
103.         if (string.IsNullOrWhiteSpace(word))
104.         {
105.             return word;
106.         }
107. 
108.         if (_uncountables.Contains(word))
109.         {
110.             return word;
111.         }
112. 
113.         if (_irregularPlurals.TryGetValue(word, out var irregularPlural))
114.         {
